+    "user.name=Test",
+    "-c",
+    "user.email=test@example.com",
+    "commit",
+    "-m",
+    "shared tooling",
+  ]);
+  const headRef = git(repoDir, ["rev-parse", "HEAD"]);
+
+  return { baseRef, headRef };
+}
